use std::collections::BinaryHeap;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let k_val = k as usize;
    let mut teleport_map = vec![vec![vec![]; n]; m];
    for i in 0..m {
        for j in 0..n {
            let current_val = grid[i][j];
            for x in 0..m {
                for y in 0..n {
                    if grid[x][y] <= current_val {
                        teleport_map[i][j].push((x as i32, y as i32));
                    }
                }
            }
        }
    }
    let mut dist = vec![vec![vec![i64::MAX; k_val + 1]; n]; m];
    dist[0][0][0] = 0;
    let mut pq = BinaryHeap::new();
    pq.push((0, 0, 0, 0));
    while let Some((cost, i, j, t)) = pq.pop() {
        if i == m - 1 && j == n - 1 {
            return cost;
        }
        if cost > dist[i][j][t] {
            continue;
        }
        // Regular moves
        if j + 1 < n {
            let new_cost = cost + grid[i][j + 1];
            if new_cost < dist[i][j + 1][t] {
                dist[i][j + 1][t] = new_cost;
                pq.push((new_cost, i, j + 1, t));
            }
        }
        if i + 1 < m {
            let new_cost = cost + grid[i + 1][j];
            if new_cost < dist[i + 1][j][t] {
                dist[i + 1][j][t] = new_cost;
                pq.push((new_cost, i + 1, j, t));
            }
        }
        // Teleportation
        if t < k_val {
            for (x, y) in &teleport_map[i][j] {
                let new_t = t + 1;
                let new_cost = cost;
                let x_us = x as usize;
                let y_us = y as usize;
                if new_cost < dist[x_us][y_us][new_t] {
                    dist[x_us][y_us][new_t] = new_cost;
                    pq.push((new_cost, x_us, y_us, new_t));
                }
            }
        }
    }
    // If not found, return the minimum of the destination row
    let mut min_cost = i64::MAX;
    for t in 0..=k_val {
        if dist[m - 1][n - 1][t] < min_cost {
            min_cost = dist[m - 1][n - 1][t];
        }
    }
    min_cost
}
